Yes, I will just copy the source code:

```c++
void FastText::getVector(Vector& vec, const std::string& word) const {
  const std::vector<int32_t>& ngrams = dict_->getSubwords(word);
  vec.zero();
  for (auto it = ngrams.begin(); it != ngrams.end(); ++it) {
    if (quant_) {
      vec.addRow(*qinput_, *it);
    } else {
      vec.addRow(*input_, *it);
    }
  }
  if (ngrams.size() > 0) {
    vec.mul(1.0 / ngrams.size());
  }
}
```

You can see that the subword vectors sum is divided by the number of subwords.
So, yes, the vector is averaged :-)

