# example file ./rive_routes/reverse.py

def revFunc(rs, args):
    text = " ".join(args)
    reversed = text[::-1]
    return reversed

def doWild(rs, args):
    return "the no response reverse wildcard. {topic=random}"

routes = {
    "topic=testtopic": {
        "reverse": {
            "triggers": [
                "say * in reverse",
                "say * to me (backward|backwards|in reverse|reversed)",
                "reverse *"
            ],
            "args": "<star1>",
            "handler": revFunc
        },
        "wildcard": {
            "triggers": ["*"],
            "args": "<star>",
