```python
# main file

import os, importlib 
from rivescript import RiveScript

bot = RiveScript()

# fetch all routes from files
allRoutes = []
for subdir, dirs, files in os.walk("./rive_routes"):
    for file in files:
        filepath = subdir + os.sep + file
        if filepath.endswith(".py") and not filepath.endswith("__init__.py"):
            filepath = filepath.replace("./", "").replace("\\", ".")[:-3]
            if filepath.startswith("."):
                filepath = filepath[1:]
            rep = getattr(importlib.import_module(filepath), "routes")
            allRoutes.append(rep)

# load routes
for routes in allRoutes:
    for t, triggers in routes.items():
        topic = "none"
        if t[6:] != "none" or "topic" not in t[6:]:
            topic = t[6:]
        trigs = ""
        for name, keys in triggers.items():
            for trig in keys["triggers"]:
                trigs += "+ " + trig + "\n" + "- <call>" + name + " " + keys["args"] + "</call>\n"
            # Register the JavaScript object macro.
            bot.set_subroutine(name, keys["handler"])
        if topic != "none":
            # set topic and triggers in stream
            bot.stream("> topic "+ topic +"\n" + trigs + "< topic\n")
        else:
            # set triggers in stream
            bot.stream(trigs)

bot.load_directory("./rives")
bot.sort_replies()

while True:
    msg = input('You> ')
    if msg == '/q':
        quit()

    reply = bot.reply("You", msg)
    print('Bot>', reply)
    
```

