             return name.replace('Fa', 'FastEthernet')
         elif name.startswith('Gi'):
             return name.replace('Gi', 'GigabitEthernet')
         else:
             #catch all
             return name

And then, in the code that is already in place:


      interface = short_to_long_iface_name(interface)

